import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { RuleMappingCreateComponent } from './rule-mapping-create/rule-mapping-create.component';
import { RuleMappingDetailsComponent } from './rule-mapping-details/rule-mapping-details.component';
import { RuleMappingComponent } from './rule-mapping/rule-mapping.component';

const routes: Routes = [
  {
    path:'create',
    component:RuleMappingCreateComponent
  },{
    path:'edit/:mapId',
    component:RuleMappingDetailsComponent
  },{
    path:'summary',
    component:RuleMappingComponent
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class RuleMappingRoutingModule { }
